import numpy as np

def softmax(x):
    e = np.exp(x - x.max(axis=-1, keepdims=True))
    return e / e.sum(axis=-1, keepdims=True)

def attention(Q, K, V):
    d_k = Q.shape[-1]
    scores = (Q @ K.swapaxes(-1, -2)) / np.sqrt(d_k)
    weights = softmax(scores)
    return weights @ V, weights

import torch

def causal_mask(T):
    # lower-triangular: position t sees 0..t only
    return torch.tril(torch.ones(T, T)).bool()

mask = causal_mask(5)
print(mask.int())   # 1s on/below the diagonal, 0s above
